async function defaultReadStdin(): Promise<string> {
  const chunks: Buffer[] = [];
  for await (const chunk of process.stdin) {
    chunks.push(chunk as Buffer);
  }
  return Buffer.concat(chunks).toString('utf-8');
}

// ─── Verdict-shape registry ─────────────────────────────────────────────
// Translates a WorkflowVerdict to stdout JSON per the operation's
// @verdictShape. Adding a new shape requires extending the union below
// AND updating the typespec-workflow VerdictShape union.

type Shape =
  | 'permission-decision'
  | 'decision-block'
  | 'permission-request'
  | 'cursor-permission'
  | 'cursor-observe'
  | 'none';

function renderVerdictOutput(
  shape: Shape,
  v: WorkflowVerdict | undefined,
  env: { hook_event_name?: string },
): unknown {
  const arm = v?.arm ?? 'allow';
  const reason = v?.reason ?? '';
  switch (shape) {
    case 'permission-decision': {
      if (arm === 'allow' || arm === 'constrain') {
        return { hookSpecificOutput: { permissionDecision: 'allow' } };
      }
      if (arm === 'require_approval') {
        return {
          hookSpecificOutput: {
            permissionDecision: 'ask',
            permissionDecisionReason: reason || 'OpenBox: approval required',
          },
        };
      }
      // block / halt
      return {
        hookSpecificOutput: {
          permissionDecision: 'deny',
          permissionDecisionReason: reason || 'OpenBox: blocked by policy',
        },
      };
    }
    case 'decision-block': {
      if (arm === 'block' || arm === 'halt') {
        return {
          decision: 'block',
          reason: reason || 'OpenBox: blocked by policy',
        };
      }
      return {};
    }
    case 'permission-request': {
      const eventName = env.hook_event_name ?? 'PermissionRequest';
      if (arm === 'allow' || arm === 'constrain') {
        return {
          hookSpecificOutput: {
            hookEventName: eventName,
            decision: { behavior: 'allow' },
          },
        };
      }
      return {
        hookSpecificOutput: {
          hookEventName: eventName,
          decision: {
            behavior: 'deny',
            message: reason || 'OpenBox: blocked by policy',
          },
        },
      };
    }
    case 'cursor-permission': {
      if (arm === 'allow' || arm === 'constrain') return { permission: 'allow' };
      if (arm === 'require_approval') {
        return {
          permission: 'deny',
          userMessage: reason || 'OpenBox: approval required',
          agentMessage: 'OpenBox: awaiting human approval',
        };
      }
      if (arm === 'halt') {
        return {
          permission: 'deny',
          userMessage: 'OpenBox HALT: ' + (reason || 'session halted'),
          agentMessage: 'OpenBox HALT: do not proceed',
        };
      }
      return {
        permission: 'deny',
        userMessage: reason || 'OpenBox: blocked by policy',
      };
    }
    case 'cursor-observe':
      return {};
    case 'none':
      return undefined;
  }
}




